def numerical_letter_grade(grades):
    """It is the last week of the semester and the teacher has to give the grades
    to students. The teacher has been making her own algorithm for grading.
    The only problem is, she has lost the code she used for grading.
    She has given you a list of GPAs for some students and you have to write 
    a function that can output a list of letter grades using the following table:
             GPA       |    Letter grade
              4.0                A+
            > 3.7                A 
            > 3.3                A- 
            > 3.0                B+
            > 2.7                B 
            > 2.3                B-
            > 2.0                C+
            > 1.7                C
            > 1.3                C-
            > 1.0                D+ 
            > 0.7                D 
            > 0.0                D-
              0.0                E


    Example:
    grade_equation([4.0, 3, 1.7, 2, 3.5]) ==> ['A+', 'B', 'C-', 'C', 'A-']
    """
    result=[]
    for g in grades:
        if(g>4 or g<0):
            raise ValueError("Invalid GPA value")
        elif g == 4:
            result.append("A+")
        elif g >3.7:
            result.append("A")
        elif g >3.3:
            result.append("A-")
        elif g >3.0:
            result.append("B+")
        elif g >2.7:
            result.append("B")
        elif g >2.3:
            result.append("B-")
        elif g >2.0:
            result.append("C+")
        elif g >1.7:
            result.append("C")
        elif g >1.3:
            result.append("C-")
        elif g >1.0:
            result.append("D+")
        elif g >0.7:
            result.append("D")
        elif g >0.0:
            result.append("D-")
        elif g == 0.0:
            result.append("E")
        else:
            raise ValueError("Invalid GPA value")
    return result

